def alienOrder(words):
    adj = collections.defaultdict(set); in_degree = {c: 0 for w in words for c in w}
    for i in range(len(words)-1):
        w1, w2 = words[i], words[i+1]
        for j in range(min(len(w1), len(w2))):
            if w1[j] != w2[j]:
                if w2[j] not in adj[w1[j]]: adj[w1[j]].add(w2[j]); in_degree[w2[j]] += 1
                break
            else:
                if j == len(w2)-1 and len(w1) > len(w2): return ""
    res = []; q = collections.deque([c for c in in_degree if in_degree[c] == 0])
    while q:
        c = q.popleft(); res.append(c)
        for n in adj[c]:
            in_degree[n] -= 1
            if in_degree[n] == 0: q.append(n)
    return "".join(res) if len(res) == len(in_degree) else ""

